VALUES
  ('heelevel3-29a002de-moex-00001', 'heelevel3-29a002de', 'heelevel3-29a002de-moex-114-916530c6', 'sub-heelevel3-29a002de-01', NULL, 'essay', '甲近來因積欠賭債，甚為煩惱。甲知其友乙生性甚為膽小，且過去有被
搶之不愉快經驗，遂於乙某日下午五時下班之際，戴上墨鏡及口罩後，
在某捷運站附近攔住乙說「嘿嘿，借點錢來花花吧」，乙聞後說「好的、
好的」，並掏出口袋內五千元給甲後，立刻跑離現場。甲之行為該如何論
處？（25分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:32:38+00:00", "source_pdf_sha1": "11be7e46a91d", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "114080", "c": "227", "s": "0913", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "刑法", "year": "114", "exam_name": "114年公務人員高等考試三級考試暨普通考試", "original_question_number": "一", "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "司法行政"}'::jsonb, NULL),
  ('heelevel3-29a002de-moex-00002', 'heelevel3-29a002de', 'heelevel3-29a002de-moex-114-916530c6', 'sub-heelevel3-29a002de-01', NULL, 'essay', '甲乙為好友，甲知乙之詐騙組織一時欠缺資金，遂借新臺幣一百萬元給乙
使用。未料乙運氣甚好，不久後簽中樂透大獎，資金充裕，根本用不到甲
的借款，於是返還甲新臺幣一百萬元。試問甲是否構成犯罪？（25分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:32:38+00:00", "source_pdf_sha1": "11be7e46a91d", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "114080", "c": "227", "s": "0913", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "刑法", "year": "114", "exam_name": "114年公務人員高等考試三級考試暨普通考試", "original_question_number": "二", "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "司法行政"}'::jsonb, NULL),
  ('heelevel3-29a002de-moex-00003', 'heelevel3-29a002de', 'heelevel3-29a002de-moex-114-916530c6', 'sub-heelevel3-29a002de-01', NULL, 'single_choice', '依我國實務見解，下列何種犯行已經達到刑法第25條所稱著手實行時點，而可成立未遂罪名？', '["甲出於殺害乙之意思，躲在乙家樓下待乙現身，惟乙當日出國", "甲出於侵入住居以竊取乙家財物意思，前往乙家附近向其鄰居丙打探乙之行蹤", "甲出於放火之意思，在乙住家附近潑澆汽油", "甲出於將被害人迷暈再為強制性交之意思，在乙的飲料內投入昏迷用藥劑"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:32:38+00:00", "source_pdf_sha1": "11be7e46a91d", "answer_pdf_sha1": "2951af1e823c", "source_family": "moex-gov-tw", "moex": {"exam_code": "114080", "c": "227", "s": "0913", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "刑法", "year": "114", "exam_name": "114年公務人員高等考試三級考試暨普通考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "司法行政"}'::jsonb, NULL),
  ('heelevel3-29a002de-moex-00004', 'heelevel3-29a002de', 'heelevel3-29a002de-moex-114-916530c6', 'sub-heelevel3-29a002de-01', NULL, 'single_choice', '下列何者不是刑法意義的公務員？', '["競選獲勝已宣誓就職之鄉民代表", "辦理政府研究計畫之國立大學教授", "公立學校之辦理採購人員", "受委託辦理汽車定期檢查之民間修車場員工"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:32:38+00:00", "source_pdf_sha1": "11be7e46a91d", "answer_pdf_sha1": "2951af1e823c", "source_family": "moex-gov-tw", "moex": {"exam_code": "114080", "c": "227", "s": "0913", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "刑法", "year": "114", "exam_name": "114年公務人員高等考試三級考試暨普通考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "司法行政"}'::jsonb, NULL),
  ('heelevel3-29a002de-moex-00005', 'heelevel3-29a002de', 'heelevel3-29a002de-moex-114-916530c6', 'sub-heelevel3-29a002de-01', NULL, 'single_choice', '依我國實務見解，下列何者不成立共同正犯？', '["參與殺人計畫謀議之黑社會老大", "未參與謀議，僅出賣人頭帳戶給不知名集團之家庭主婦", "於詐欺被害人轉錢至人頭帳戶後，於明知相關情事下，受聘於詐欺集團擔任取款車手，而於提 款機領取該款項之高中生", "出於共同犯意，而於他人實行強制性交行為時，在一旁抓住被害人的黑社會小弟"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:32:38+00:00", "source_pdf_sha1": "11be7e46a91d", "answer_pdf_sha1": "2951af1e823c", "source_family": "moex-gov-tw", "moex": {"exam_code": "114080", "c": "227", "s": "0913", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "刑法", "year": "114", "exam_name": "114年公務人員高等考試三級考試暨普通考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "司法行政"}'::jsonb, NULL),
  ('heelevel3-29a002de-moex-00006', 'heelevel3-29a002de', 'heelevel3-29a002de-moex-114-916530c6', 'sub-heelevel3-29a002de-01', NULL, 'single_choice', '刑法第214條規定：「明知為不實之事項，而使公務員登載於職務上所掌之公文書，足以生損害於 公眾或他人者」，有關本罪之敘述，何者錯誤？', '["本罪之行為主體須有公務員資格", "行為人主觀上須明知登載事實係為不實內容", "本罪須足生損害於公眾或他人，係屬危險犯", "本罪非繼續犯"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:32:38+00:00", "source_pdf_sha1": "11be7e46a91d", "answer_pdf_sha1": "2951af1e823c", "source_family": "moex-gov-tw", "moex": {"exam_code": "114080", "c": "227", "s": "0913", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "刑法", "year": "114", "exam_name": "114年公務人員高等考試三級考試暨普通考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "司法行政"}'::jsonb, NULL),
  ('heelevel3-29a002de-moex-00007', 'heelevel3-29a002de', 'heelevel3-29a002de-moex-114-916530c6', 'sub-heelevel3-29a002de-01', NULL, 'single_choice', '下列何種情況之甲，不會對乙產生應保護其法益之保證人地位？', '["甲為新生兒乙之母親，而甲不為生存必要的養育措施", "甲為客輪船長，而乙為該客輪之乘客，於海難發生時甲自行逃亡", "甲為公車乘客，而甲鄰座乘客乙突然在公車上發生昏迷，甲立即離開現場", "甲自行接受丙母親委託，而於晚上照顧患有嚴重氣喘乙子，未料甲看電視入迷而未給予乙藥物"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:32:38+00:00", "source_pdf_sha1": "11be7e46a91d", "answer_pdf_sha1": "2951af1e823c", "source_family": "moex-gov-tw", "moex": {"exam_code": "114080", "c": "227", "s": "0913", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "刑法", "year": "114", "exam_name": "114年公務人員高等考試三級考試暨普通考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "司法行政"}'::jsonb, NULL),
  ('heelevel3-29a002de-moex-00008', 'heelevel3-29a002de', 'heelevel3-29a002de-moex-114-916530c6', 'sub-heelevel3-29a002de-01', NULL, 'single_choice', '下列有關罪刑法定原則之敘述，何者錯誤？', '["罪刑法定原則不僅是刑法原則，亦為憲法原則", "不論有利或不利被告，刑法一律禁止類推適用", "空白構成要件的刑事立法尚未牴觸罪刑法定原則", "習慣法僅得作為解釋成文法之參考依據，不得作為定罪之依據"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:32:38+00:00", "source_pdf_sha1": "11be7e46a91d", "answer_pdf_sha1": "2951af1e823c", "source_family": "moex-gov-tw", "moex": {"exam_code": "114080", "c": "227", "s": "0913", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "刑法", "year": "114", "exam_name": "114年公務人員高等考試三級考試暨普通考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "司法行政"}'::jsonb, NULL),
  ('heelevel3-29a002de-moex-00009', 'heelevel3-29a002de', 'heelevel3-29a002de-moex-114-916530c6', 'sub-heelevel3-29a002de-01', NULL, 'single_choice', '下列何者並非刑法第150條之聚集而施強暴脅迫罪之行為人？', '["甲為公共場所聚集五人之一，且下手實施強暴行為", "乙為公共場所聚集三人之一，雖未下手，但居於首謀地位，而由他人施脅迫行為", "丙為公共場所聚集四人之一，於他人下手實施強暴行為時，純粹在場觀看", "丁為公共場所聚集六人之一，於他人下手實施強暴行為時，在場呼叫助勢"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:32:38+00:00", "source_pdf_sha1": "11be7e46a91d", "answer_pdf_sha1": "2951af1e823c", "source_family": "moex-gov-tw", "moex": {"exam_code": "114080", "c": "227", "s": "0913", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "刑法", "year": "114", "exam_name": "114年公務人員高等考試三級考試暨普通考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "司法行政"}'::jsonb, NULL),
  ('heelevel3-29a002de-moex-00010', 'heelevel3-29a002de', 'heelevel3-29a002de-moex-114-916530c6', 'sub-heelevel3-29a002de-01', NULL, 'single_choice', '下列何者非屬刑法第161條第1項脫逃罪所稱依法逮捕、拘禁之人？', '["受羈押之被告", "受民事管收之債務人", "被檢察官依法拘提到案之被告", "被法院傳喚至審判庭之證人"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:32:38+00:00", "source_pdf_sha1": "11be7e46a91d", "answer_pdf_sha1": "2951af1e823c", "source_family": "moex-gov-tw", "moex": {"exam_code": "114080", "c": "227", "s": "0913", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "刑法", "year": "114", "exam_name": "114年公務人員高等考試三級考試暨普通考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "司法行政"}'::jsonb, NULL)
